  if (tab === 'relationships') {
    return <ResourceGraphTab namespace={row.namespace} kind="DaemonSet" name={row.name} />;
  }
  if (tab === 'holmes') {
    const key = `${row.namespace}/${row.name}`;
    return (
      <HolmesBottomPanel
        kind="DaemonSet"
        namespace={row.namespace}
        name={row.name}
