type StatefulSetsOverviewTableProps = {
	namespaces?: string[];
	namespace?: string;
};

export default function StatefulSetsOverviewTable({ namespaces, namespace }: StatefulSetsOverviewTableProps) {
	const [items, setItems] = useState<StatefulSetRow[]>([]);
	const [loading, setLoading] = useState(true);
	const [holmesState, setHolmesState] = useState<HolmesState>({
		loading: false,
		response: null,
		error: null,
		key: null,
		streamId: null,
		streamingText: '',
		reasoningText: '',
		queryTimestamp: null,
		contextSteps: [],
		toolEvents: [],
	});
	const holmesStateRef = useRef<HolmesState>(holmesState);
	useEffect(() => {
		holmesStateRef.current = holmesState;
	}, [holmesState]);

	// Subscribe to Holmes chat stream events
	useEffect(() => {
		const unsubscribe = onHolmesChatStream((payload) => {
			if (!payload) return;
			const current = holmesStateRef.current;
			const { streamId } = current;
			if (payload.stream_id && streamId && payload.stream_id !== streamId) {
				return;
			}
			if (payload.error) {
				if (payload.error === 'context canceled' || payload.error === 'context cancelled') {
					setHolmesState((prev) => ({ ...prev, loading: false }));
					return;
				}
				setHolmesState((prev) => ({ ...prev, loading: false, error: String(payload.error) }));
				return;
			}

			const eventType = payload.event;
			if (!payload.data) {
				return;
			}

			let data: Record<string, unknown> | null;
			try {
				data = JSON.parse(payload.data);
			} catch {
				data = null;
			}

			if (eventType === 'ai_message' && data) {
				let handled = false;
				const reasoning = typeof data.reasoning === 'string' ? data.reasoning : '';
				if (reasoning) {
					setHolmesState((prev) => ({
						...prev,
						reasoningText: (prev.reasoningText ? prev.reasoningText + '\n' : '') + reasoning,
					}));
					handled = true;
				}
				const content = typeof data.content === 'string' ? data.content : '';
				if (content) {
					setHolmesState((prev) => {
						const nextText = (prev.streamingText ? prev.streamingText + '\n' : '') + content;
						return { ...prev, streamingText: nextText, response: { response: nextText } };
					});
					handled = true;
				}
				if (handled) return;
			}

			if (eventType === 'start_tool_calling' && data && data.id !== undefined) {
				const id = String(data.id);
				const name = typeof data.tool_name === 'string' ? data.tool_name : 'tool';
				const description = typeof data.description === 'string' ? data.description : undefined;
				setHolmesState((prev) => ({
					...prev,
					toolEvents: [...(prev.toolEvents || []), {
						id,
						name,
						status: 'running',
						description,
					}],
				}));
				return;
			}

			if (eventType === 'tool_calling_result' && data && data.tool_call_id !== undefined) {
				const toolId = String(data.tool_call_id);
				const result = data.result as { status?: unknown } | undefined;
				const status = typeof result?.status === 'string'
					? result.status
					: typeof data.status === 'string'
						? data.status
						: 'done';
				const description = typeof data.description === 'string' ? data.description : undefined;
				setHolmesState((prev) => ({
					...prev,
					toolEvents: (prev.toolEvents || []).map((item) =>
						item.id === toolId
							? { ...item, status, description: description ?? item.description }
							: item
					),
				}));
				return;
			}

			if (eventType === 'ai_answer_end' && data && typeof data.analysis === 'string') {
				const analysisText = data.analysis;
				setHolmesState((prev) => ({
					...prev,
					loading: false,
					response: { response: analysisText },
					streamingText: analysisText,
				}));
				return;
			}

			if (eventType === 'stream_end') {
				setHolmesState((prev) => {
					if (prev.streamingText) {
						return { ...prev, loading: false, response: { response: prev.streamingText } };
					}
					return { ...prev, loading: false };
				});
			}
		});
		return () => {
			try { unsubscribe?.(); } catch { /* ignore */ }
		};
	}, []);

	useEffect(() => {
		const unsubscribe = onHolmesContextProgress((event: HolmesContextProgressEvent | null) => {
			if (!event?.key) return;
			setHolmesState((prev) => {
				if (prev.key !== event.key) return prev;
				const id = event.step || 'step';
				const nextSteps = Array.isArray(prev.contextSteps) ? [...prev.contextSteps] : [];
				const idx = nextSteps.findIndex((item) => item.id === id);
				const entry = {
					id,
					step: event.step,
					status: event.status || 'running',
					detail: event.detail || '',
				};
				if (idx >= 0) {
					nextSteps[idx] = { ...nextSteps[idx], ...entry };
				} else {
					nextSteps.push(entry);
				}
				return { ...prev, contextSteps: nextSteps };
			});
		});
		return () => {
			try { unsubscribe?.(); } catch { /* ignore */ }
		};
	}, []);

	// Aggregate fetch by namespaces
	useEffect(() => {
		const nsArr = Array.isArray(namespaces) && namespaces.length > 0 ? namespaces : (namespace ? [namespace] : []);
		if (nsArr.length === 0) return;
		let cancelled = false;
		const run = async () => {
			try {
				setLoading(true);
				const lists = await Promise.all(nsArr.map(ns => AppAPI.GetStatefulSets(ns).catch(() => [])));
				if (cancelled) return;
				const flat = lists.flat().map((x) => normalizeStatefulSet(x as StatefulSetInfoRaw));
				setItems(flat);
			} catch (_e) {
				if (!cancelled) setItems([]);
			} finally {
				if (!cancelled) setLoading(false);
			}
		};
		run();
		return () => { cancelled = true; };
	}, [namespaces, namespace]);

	// Live updates (already aggregated by backend polling)
	useEffect(() => {
		const onUpdate = (list: unknown) => {
			try {
				const arr = Array.isArray(list) ? list : [];
				const norm = arr.map((x) => normalizeStatefulSet(x as StatefulSetInfoRaw));
				setItems(norm);
			} catch {
				setItems([]);
			} finally {
				setLoading(false);
			}
		};
		EventsOn('statefulsets:update', onUpdate);
		return () => { try { EventsOff('statefulsets:update'); } catch { /* ignore */ } };
	}, []);
	const analyzeStatefulSet = async (row: StatefulSetRow) => {
		const key = `${row.namespace}/${row.name}`;
		const streamId = `statefulset-${Date.now()}`;
		setHolmesState({
			loading: true,
			response: null,
			error: null,
			key,
			streamId,
			streamingText: '',
			reasoningText: '',
			queryTimestamp: new Date().toISOString(),
			contextSteps: [],
			toolEvents: [],
		});
		try {
			await AnalyzeStatefulSetStream(row.namespace, row.name, streamId);
			// The response comes via stream events, not from the return value
		} catch (err) {
			const message = err instanceof Error ? err.message : String(err);
			setHolmesState((prev) => ({ ...prev, loading: false, response: null, error: message, key }));
			showError(`Holmes analysis failed: ${message}`);
		}
	};

	const cancelHolmesAnalysis = async () => {
		const currentStreamId = holmesState.streamId;
		if (!currentStreamId) return;
		setHolmesState((prev) => ({ ...prev, loading: false, streamId: null }));
		try {
			await CancelHolmesStream(currentStreamId);
		} catch (err) {
			console.error('Failed to cancel Holmes stream:', err);
		}
	};

	const getRowActions = (row: StatefulSetRow, api: { openDetails?: (_tabKey?: string) => void }) => {
		const key = `${row.namespace}/${row.name}`;
		const isAnalyzing = holmesState.loading && holmesState.key === key;
		return [
			{
				label: isAnalyzing ? 'Analyzing...' : 'Ask Holmes',
				icon: '🧠',
				disabled: isAnalyzing,
				onClick: () => {
					analyzeStatefulSet(row);
					api?.openDetails?.('holmes');
				},
			},
			{
				label: 'Restart',
				icon: '🔄',
				onClick: async () => {
					try {
						if (AppAPI.RestartStatefulSet) {
							await AppAPI.RestartStatefulSet(row.namespace, row.name);
							showSuccess(`StatefulSet '${row.name}' restarted`);
						} else {
							showError('RestartStatefulSet API unavailable');
						}
					} catch (err) {
						showError(`Failed to restart StatefulSet '${row.name}': ${err instanceof Error ? err.message : err}`);
					}
				},
			},
			{
				label: 'Delete',
				icon: '🗑️',
				danger: true,
				onClick: async () => {
					try {
						await AppAPI.DeleteResource('statefulset', row.namespace, row.name);
						showSuccess(`StatefulSet '${row.name}' deleted`);
					} catch (err) {
						showError(`Failed to delete StatefulSet '${row.name}': ${err instanceof Error ? err.message : err}`);
					}
				},
			},
		];
	};

	return (
		<OverviewTableWithPanel
			columns={columns}
			data={items}
			tabs={bottomTabs}
			renderPanelContent={(row, tab) => renderPanelContent(row, tab, holmesState, analyzeStatefulSet, cancelHolmesAnalysis)}
			panelHeader={panelHeader}
			title="Stateful Sets"
			resourceKind="StatefulSet"
			namespace={namespace}
			loading={loading}
			getRowActions={getRowActions}
		/>
	);
}

export { StatefulSetsOverviewTable };

import { Fragment, useCallback, useEffect, useMemo, useRef, useState } from 'react';
import * as AppAPI from '../../../wailsjs/go/main/App';
import { Compartment, EditorState } from '@codemirror/state';
import { EditorView, keymap, lineNumbers, highlightActiveLineGutter } from '@codemirror/view';
import { foldGutter, foldKeymap, defaultHighlightStyle, syntaxHighlighting } from '@codemirror/language';
import { yaml as yamlLang } from '@codemirror/lang-yaml';
import { pickDefaultSortKey, sortRows, toggleSortState } from '../../utils/tableSorting';

type FileEntry = {
  path: string;
  name: string;
  isDir?: boolean;
  isSymlink?: boolean;
  linkTarget?: string;
  mode?: string;
  size?: number;
  modified?: string;
};

type FileContent = {
  path: string;
  text: string;
  truncated: boolean;
  isBinary: boolean;
  size?: number;
};

type FilesTabProps = {
  namespace?: string;
  pvcName?: string;
};

type SortState = { key: string; direction: 'asc' | 'desc' };

export default function FilesTab({ namespace, pvcName }: FilesTabProps) {
  const [path, setPath] = useState('/');
  const [entries, setEntries] = useState<FileEntry[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [fileContent, setFileContent] = useState<FileContent | null>(null);
  const [contentLoading, setContentLoading] = useState(false);
  const [contentError, setContentError] = useState<string | null>(null);
  const [downloading, setDownloading] = useState(false);
  const [downloadError, setDownloadError] = useState<string | null>(null);
  const columns = useMemo(
    () => [
      { key: 'name', label: 'Name' },
      { key: 'mode', label: 'Perms' },
      { key: 'size', label: 'Size' },
      { key: 'modified', label: 'Modified' },
    ],
    []
  );
  const defaultSortKey = useMemo(() => pickDefaultSortKey(columns), [columns]);
  const [sortState, setSortState] = useState<SortState>(() => ({
    key: defaultSortKey,
    direction: 'asc',
  }));

  const editorParentRef = useRef<HTMLDivElement | null>(null);
  const cmViewRef = useRef<EditorView | null>(null);
  const languageCompartmentRef = useRef(new Compartment());

  const cmTheme = useMemo(
    () =>
      EditorView.theme(
        {
          '&': { backgroundColor: '#0d1117', color: '#c9d1d9' },
          '&.cm-editor': { height: '100%', width: '100%' },
          '.cm-scroller': {
            fontFamily:
              'ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace',
            lineHeight: '1.4',
          },
          '.cm-gutters': { background: '#161b22', color: '#8b949e', borderRight: '1px solid #30363d' },
        },
        { dark: true }
      ),
    []
  );

  const cmExtensions = useMemo(
    () => [
      cmTheme,
      lineNumbers(),
      highlightActiveLineGutter(),
      foldGutter(),
      keymap.of(foldKeymap),
      languageCompartmentRef.current.of([]),
      syntaxHighlighting(defaultHighlightStyle),
      EditorView.lineWrapping,
      EditorView.editable.of(false),
      EditorState.readOnly.of(true),
    ],
    [cmTheme]
  );

  const initOrUpdateEditor = useCallback(
    (text: string, filePath = '') => {
      if (!editorParentRef.current) return;
      const lower = (filePath || '').toLowerCase();
      const languageExt = lower.endsWith('.yaml') || lower.endsWith('.yml') ? [yamlLang()] : [];
      if (!cmViewRef.current) {
        const state = EditorState.create({ doc: text || '', extensions: cmExtensions });
        cmViewRef.current = new EditorView({ state, parent: editorParentRef.current });
      }

      cmViewRef.current.dispatch({
        effects: languageCompartmentRef.current.reconfigure(languageExt),
        changes: { from: 0, to: cmViewRef.current.state.doc.length, insert: text || '' },
      });
    },
    [cmExtensions]
  );

  useEffect(
    () =>
      () => {
        if (cmViewRef.current) {
          try {
            cmViewRef.current.destroy();
          } catch (_e) {}
          cmViewRef.current = null;
        }
      },
    []
  );

  const iconFor = (e: FileEntry) => {
    if (e.isDir) return '📁';
    if (e.isSymlink) return '🔗';
    const name = e.name.toLowerCase();
    if (name.endsWith('.log')) return '🧾';
    if (name.endsWith('.yaml') || name.endsWith('.yml')) return '📝';
    if (name.endsWith('.json')) return '🗂';
    if (name.endsWith('.sh')) return '🐚';
    if (name.endsWith('.txt')) return '📄';
    return '📦';
  };

  const humanSize = (n: number | string | null | undefined) => {
    if (n === '-' || n == null) return '-';
    const num = Number(n);
    if (isNaN(num)) return String(n);
    if (num < 1024) return `${num} B`;
    const units = ['KiB', 'MiB', 'GiB', 'TiB'];
    let v = num;
    let u = -1;
    while (v >= 1024 && u < units.length - 1) {
      v /= 1024;
      u++;
    }
    return `${v.toFixed(1)} ${units[u]}`;
  };

  const loadDir = useCallback(
    async (targetPath: string) => {
      if (!namespace || !pvcName) return;
      setLoading(true);
      setError(null);
      setFileContent(null);
      setContentError(null);
      try {
        const list = await AppAPI.ListPVCFiles(namespace, pvcName, targetPath);
        setEntries(Array.isArray(list) ? (list as FileEntry[]) : []);
        setPath(targetPath);
      } catch (e: unknown) {
        setError((e as Error)?.message || String(e));
        setEntries([]);
      } finally {
        setLoading(false);
      }
    },
    [namespace, pvcName]
  );

  useEffect(() => {
    loadDir('/');
  }, [loadDir]);

  const breadcrumbs = path === '/' ? [''] : path.split('/').filter(Boolean);

  useEffect(() => {
    if (!defaultSortKey) return;
    setSortState((cur) => (cur?.key ? cur : { key: defaultSortKey, direction: 'asc' }));
  }, [defaultSortKey]);

  const handleCrumbClick = (idx: number) => {
    if (idx === -1) {
      loadDir('/');
      return;
    }
    const newPath = '/' + breadcrumbs.slice(0, idx + 1).join('/');
    loadDir(newPath === '' ? '/' : newPath);
  };

  const openEntry = (entry: FileEntry) => {
    if (entry.isDir) {
      loadDir(entry.path);
    } else {
      fetchFile(entry.path);
    }
  };

  const fetchFile = async (filePath: string) => {
    setContentLoading(true);
    setContentError(null);
    setFileContent(null);
    try {
      const res = await AppAPI.GetPVCFileContent(namespace || '', pvcName || '', filePath, 262144);
      let text = '';
      if (!res.isBinary) {
        try {
          text = atob(res.base64 || '');
        } catch {
          text = '[decode error]';
        }
      }
      const fc: FileContent = {
        path: res.path,
        truncated: !!res.truncated,
        isBinary: !!res.isBinary,
        size: res.size,
        text,
      };
      setFileContent(fc);
      if (!fc.isBinary) initOrUpdateEditor(fc.text, fc.path);
    } catch (e: unknown) {
      setContentError((e as Error)?.message || String(e));
    } finally {
      setContentLoading(false);
    }
  };

  const downloadArchive = async (targetPath: string) => {
    setDownloadError(null);
    setDownloading(true);
    try {
      const res = await AppAPI.ArchivePVCPath(namespace || '', pvcName || '', targetPath, 0);
      const blob = base64TarToBlob(res.base64);
      const nameSeg = targetPath === '/' ? 'root' : targetPath.split('/').filter(Boolean).pop();
      const filename = `${pvcName}-${nameSeg || 'root'}.tar.gz`;
      triggerBlobDownload(blob, filename);
      if (res.truncated) setDownloadError('Archive truncated by server limit');
    } catch (e: unknown) {
      setDownloadError((e as Error)?.message || String(e));
    } finally {
      setDownloading(false);
    }
  };

  const base64TarToBlob = (b64: string) => {
    try {
      const bytes = Uint8Array.from(atob(b64 || ''), (c) => c.charCodeAt(0));
      return new Blob([bytes], { type: 'application/gzip' });
    } catch {
      return new Blob([]);
    }
  };

  const triggerBlobDownload = (blob: Blob, name: string) => {
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = name;
    document.body.appendChild(a);
    a.click();
    setTimeout(() => {
      URL.revokeObjectURL(url);
      a.remove();
    }, 0);
  };

  const sortedEntries = useMemo(() => {
    return sortRows(entries, sortState.key, sortState.direction, (row: FileEntry, key: string) => {
      if (key === 'size') return row?.isDir ? null : row?.size;
      return (row as Record<string, unknown>)?.[key];
    });
  }, [entries, sortState]);

  const headerButtonStyle: React.CSSProperties = {
    width: '100%',
    background: 'transparent',
    border: 'none',
    color: 'inherit',
    font: 'inherit',
    padding: 0,
    cursor: 'pointer',
    display: 'inline-flex',
    alignItems: 'center',
    justifyContent: 'space-between',
    gap: 6,
    textAlign: 'left',
  };

  return (
    <div style={{ position: 'absolute', inset: 0, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
      <div
        style={{
          padding: '8px 12px',
          background: 'var(--gh-bg-alt,#161b22)',
          borderBottom: '1px solid #30363d',
          display: 'flex',
          alignItems: 'center',
          gap: 12,
          flexWrap: 'wrap',
        }}
      >
        <span style={{ fontWeight: 600 }}>Files</span>
        <div
          style={{
            fontSize: 12,
            color: 'var(--gh-text-muted,#8b949e)',
            display: 'flex',
            alignItems: 'center',
            flexWrap: 'wrap',
          }}
        >
          <span style={{ cursor: 'pointer' }} onClick={() => handleCrumbClick(-1)}>
            root
          </span>
          {breadcrumbs.map((b, idx) => (
            <Fragment key={idx}>
              <span style={{ margin: '0 4px' }}>/</span>
              <span style={{ cursor: 'pointer' }} onClick={() => handleCrumbClick(idx)}>
                {b}
              </span>
            </Fragment>
          ))}
        </div>
        <div style={{ marginLeft: 'auto', display: 'flex', gap: 8 }}>
          <button disabled={downloading || loading} style={btnStyle} onClick={() => downloadArchive(path)}>
            {downloading ? 'Archiving...' : 'Download Dir (.tar.gz)'}
          </button>
          {fileContent && !fileContent.isBinary && (
            <button
              disabled={downloading}
              style={btnStyle}
              onClick={() => downloadArchive(fileContent.path, true)}
            >
              Download File (.tar.gz)
            </button>
          )}
        </div>
      </div>
      {downloadError && (
        <div style={{ padding: '4px 12px', background: '#2d1f1f', color: '#f85149', fontSize: 12 }}>
          {downloadError}
        </div>
      )}
      <div style={{ display: 'flex', flex: 1, minHeight: 0 }}>
        <div
          style={{ width: '50%', minWidth: 300, borderRight: '1px solid #30363d', display: 'flex', flexDirection: 'column' }}
        >
          {loading && (
            <div style={{ padding: 12, fontSize: 13, color: 'var(--gh-text-muted,#8b949e)' }}>
              Loading directory...
            </div>
          )}
          {error && (
            <div style={{ padding: 12, fontSize: 13, color: '#f85149' }}>Error: {error}</div>
          )}
          {!loading && !error && entries.length === 0 && (
            <div style={{ padding: 12, fontSize: 13, color: 'var(--gh-text-muted,#8b949e)' }}>
              Empty directory or not accessible.
            </div>
          )}
          <div style={{ overflowY: 'auto', flex: 1 }}>
            <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 12, tableLayout: 'fixed' }}>
              <thead style={{ position: 'sticky', top: 0 }}>
                <tr style={{ background: '#161b22' }}>
                  <th
                    style={thStyle}
                    aria-sort={
                      sortState.key === 'name'
                        ? sortState.direction === 'asc'
                          ? 'ascending'
                          : 'descending'
                        : 'none'
                    }
                  >
                    <button
                      type="button"
                      style={headerButtonStyle}
                      onClick={() => setSortState((cur) => toggleSortState(cur, 'name'))}
                    >
                      <span>Name</span>
                      <span aria-hidden="true">
                        {sortState.key === 'name' ? (sortState.direction === 'asc' ? '▲' : '▼') : '↕'}
                      </span>
                    </button>
                  </th>
                  <th
                    style={thStyle}
                    aria-sort={
                      sortState.key === 'mode'
                        ? sortState.direction === 'asc'
                          ? 'ascending'
                          : 'descending'
                        : 'none'
                    }
                  >
                    <button
                      type="button"
                      style={headerButtonStyle}
                      onClick={() => setSortState((cur) => toggleSortState(cur, 'mode'))}
                    >
                      <span>Perms</span>
                      <span aria-hidden="true">
                        {sortState.key === 'mode' ? (sortState.direction === 'asc' ? '▲' : '▼') : '↕'}
                      </span>
                    </button>
                  </th>
                  <th
                    style={{ ...thStyle, textAlign: 'right' }}
                    aria-sort={
                      sortState.key === 'size'
                        ? sortState.direction === 'asc'
                          ? 'ascending'
                          : 'descending'
                        : 'none'
                    }
                  >
                    <button
                      type="button"
                      style={{ ...headerButtonStyle, justifyContent: 'flex-end' }}
                      onClick={() => setSortState((cur) => toggleSortState(cur, 'size'))}
                    >
                      <span>Size</span>
                      <span aria-hidden="true">
                        {sortState.key === 'size' ? (sortState.direction === 'asc' ? '▲' : '▼') : '↕'}
                      </span>
                    </button>
                  </th>
                  <th
                    style={thStyle}
                    aria-sort={
                      sortState.key === 'modified'
                        ? sortState.direction === 'asc'
                          ? 'ascending'
                          : 'descending'
                        : 'none'
                    }
                  >
                    <button
                      type="button"
                      style={headerButtonStyle}
                      onClick={() => setSortState((cur) => toggleSortState(cur, 'modified'))}
                    >
                      <span>Modified</span>
                      <span aria-hidden="true">
                        {sortState.key === 'modified' ? (sortState.direction === 'asc' ? '▲' : '▼') : '↕'}
                      </span>
                    </button>
                  </th>
                </tr>
              </thead>
              <tbody>
                {sortedEntries.map((e) => (
                  <tr
                    key={e.path}
                    onClick={() => openEntry(e)}
                    style={{ cursor: 'pointer' }}
                    className={e.isDir ? 'dir-row' : 'file-row'}
                  >
                    <td
                      style={{
                        padding: '4px 8px',
                        color: e.isDir ? '#58a6ff' : 'var(--gh-text,#c9d1d9)',
                        display: 'flex',
                        gap: 6,
                        alignItems: 'center',
                      }}
                    >
                      <span>{iconFor(e)}</span>
                      <span>
                        {e.name}
                        {e.isSymlink && e.linkTarget ? (
                          <span style={{ color: '#8b949e' }}> ➜ {e.linkTarget}</span>
                        ) : null}
                      </span>
                    </td>
                    <td style={{ padding: '4px 8px', color: 'var(--gh-text-muted,#8b949e)', whiteSpace: 'nowrap' }}>
                      {e.mode || ''}
                    </td>
                    <td style={{ padding: '4px 8px', textAlign: 'right', color: 'var(--gh-text-muted,#8b949e)' }}>
                      {e.isDir ? '-' : humanSize(e.size)}
                    </td>
                    <td style={{ padding: '4px 8px', color: 'var(--gh-text-muted,#8b949e)' }}>
                      {e.modified ? e.modified.replace('T', ' ') : ''}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
        <div style={{ flex: 1, display: 'flex', flexDirection: 'column', minWidth: 0 }}>
          {!fileContent && !contentLoading && !contentError && (
            <div style={{ padding: 16, fontSize: 13, color: 'var(--gh-text-muted,#8b949e)' }}>
              Select a file to preview (text up to 256 KiB). Binary files not shown. Helper pod may auto‑start if none mounts this PVC.
            </div>
          )}
          {contentLoading && (
            <div style={{ padding: 16, fontSize: 13, color: 'var(--gh-text-muted,#8b949e)' }}>
              Loading file...
            </div>
          )}
          {contentError && (
            <div style={{ padding: 16, fontSize: 13, color: '#f85149' }}>Error: {contentError}</div>
          )}
          {fileContent && fileContent.isBinary && (
            <div style={{ padding: 16, fontSize: 13, color: 'var(--gh-text-muted,#8b949e)' }}>
              {fileContent.path} is a binary file ({humanSize(fileContent.size)}). Preview disabled. You can still download the directory or file as an archive.
            </div>
          )}
          {fileContent && !fileContent.isBinary && (
            <div style={{ display: 'flex', flexDirection: 'column', flex: 1, minHeight: 0 }}>
              <div
                style={{
                  padding: '6px 10px',
                  background: '#161b22',
                  borderBottom: '1px solid #30363d',
                  fontSize: 12,
                  display: 'flex',
                  justifyContent: 'space-between',
                  alignItems: 'center',
                }}
              >
                <span style={{ whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{fileContent.path}</span>
                <span style={{ color: 'var(--gh-text-muted,#8b949e)' }}>
                  {humanSize(fileContent.size)}{fileContent.truncated ? ' (truncated)' : ''}
                </span>
              </div>
              <div style={{ flex: 1, minHeight: 0 }}>
                <div ref={editorParentRef} style={{ height: '100%', width: '100%' }} />
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

const btnStyle: React.CSSProperties = {
  background: 'var(--gh-accent,#238636)',
  color: '#fff',
  border: '1px solid #2ea043',
  padding: '4px 10px',
  borderRadius: 6,
  cursor: 'pointer',
  fontSize: 12,
  fontWeight: 600,
};

const thStyle: React.CSSProperties = {
  textAlign: 'left',
  padding: '4px 8px',
  fontWeight: 500,
  whiteSpace: 'nowrap',
};

import { useEffect, useMemo, useRef } from 'react';
import { EditorView, lineNumbers, highlightActiveLineGutter, keymap } from '@codemirror/view';
import { Compartment, EditorState } from '@codemirror/state';
import { foldGutter, foldKeymap } from '@codemirror/language';
import { getCodeMirrorLanguageExtensions } from '../../utils/codeMirrorLanguage';

type TextViewerTabProps = {
  content?: string;
  filename?: string;
  loading?: boolean;
  error?: string | Error | null;
  loadingLabel?: string;
};

export default function TextViewerTab({
  content,
  filename,
  loading = false,
  error = null,
  loadingLabel = 'Loading...',
}: TextViewerTabProps) {
  const editorParentRef = useRef<HTMLDivElement | null>(null);
  const viewRef = useRef<EditorView | null>(null);
  const languageCompartmentRef = useRef(new Compartment());

  const cmTheme = useMemo(
    () =>
      EditorView.theme(
        {
          '&': { backgroundColor: '#0d1117', color: '#c9d1d9' },
          '&.cm-editor': { height: '100%', width: '100%' },
          '.cm-content': { caretColor: '#fff', textAlign: 'left' },
          '.cm-line': { textAlign: 'left' },
          '.cm-scroller': {
            fontFamily:
              'ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace',
            lineHeight: '1.45',
          },
          '.cm-whitespace': { opacity: 0.35 },
          '.cm-gutters': { background: '#161b22', color: '#8b949e', borderRight: '1px solid #30363d' },
          '.cm-gutterElement': { padding: '0 8px' },
        },
        { dark: true }
      ),
    []
  );

  const languageExtensions = useMemo(
    () => getCodeMirrorLanguageExtensions(filename, content),
    [filename, content]
  );

  const cmExtensions = useMemo(
    () => [
      cmTheme,
      lineNumbers(),
      highlightActiveLineGutter(),
      foldGutter(),
      keymap.of(foldKeymap),
      EditorView.lineWrapping,
      EditorView.editable.of(false),
      EditorState.readOnly.of(true),
      languageCompartmentRef.current.of(languageExtensions),
    ],
    [cmTheme, languageExtensions]
  );

  useEffect(() => {
    if (!editorParentRef.current) return;

    if (viewRef.current) return;
    try {
      const state = EditorState.create({
        doc: content || '',
        extensions: cmExtensions,
      });
      viewRef.current = new EditorView({
        state,
        parent: editorParentRef.current,
      });
    } catch (e) {
      console.error('Error creating CodeMirror editor:', e);
    }

    return () => {
      if (viewRef.current) {
        try {
          viewRef.current.destroy();
        } catch (e) {
          console.error('Error destroying CodeMirror editor:', e);
        } finally {
          viewRef.current = null;
        }
      }
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [cmExtensions]);

  useEffect(() => {
    const view = viewRef.current;
    if (!view) return;
    const next = content || '';
    const current = view.state.doc.toString();
    if (current === next) return;
    view.dispatch({ changes: { from: 0, to: current.length, insert: next } });
  }, [content]);

  useEffect(() => {
    const view = viewRef.current;
    if (!view) return;
    try {
      view.dispatch({ effects: languageCompartmentRef.current.reconfigure(languageExtensions) });
    } catch (_e) {
      // Best-effort; keep viewer functional even if language reconfigure fails.
    }
  }, [languageExtensions]);

  if (loading) {
    return (
      <div
        style={{
          padding: 20,
          textAlign: 'center',
          color: 'var(--gh-text-muted, #8b949e)',
          height: '100%',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
        }}
      >
        {loadingLabel}
      </div>
    );
  }

  if (error) {
    return (
      <div
        style={{
          padding: 20,
          color: '#f85149',
          height: '100%',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          flexDirection: 'column',
        }}
      >
        <div style={{ marginBottom: 8 }}>Error:</div>
        <div style={{ fontSize: 14 }}>{String(error)}</div>
      </div>
    );
  }

  return (
    <div style={{ height: '100%', width: '100%', overflow: 'hidden' }}>
      <div ref={editorParentRef} style={{ height: '100%', width: '100%' }} />
    </div>
  );
}

/* eslint-disable @typescript-eslint/no-explicit-any */
/* eslint-disable @typescript-eslint/no-unused-vars */
import { useCallback, useEffect, useMemo, useRef, useState, type ReactNode } from 'react';
import { executeBulkAction } from '../../api/bulkOperations';
import { fetchTabCounts } from '../../api/tabCounts';
import BulkActionBar from '../../components/BulkActionBar';
import StatusBadge from '../../components/StatusBadge';
import { getBulkActionsForResource, type BulkAction } from '../../constants/bulkActions';
import CreateManifestOverlay from '../../CreateManifestOverlay';
import useTableSelection from '../../hooks/useTableSelection';
import { showError, showNotification, showSuccess } from '../../notification';
import { getColumnKey, pickDefaultSortKey, sortRows, toggleSortState } from '../../utils/tableSorting';
import BottomPanel from '../bottompanel/BottomPanel';
import './BulkSelection.css';
import './OverviewTableWithPanel.css';
const STATUS_BADGE_KEYS = new Set(['status', 'state', 'availability', 'phase']);

type ColumnDef = {
  key?: string;
  label?: string;
  header?: string;
  accessorKey?: string;
  width?: string | number;
  cell?: (_ctx: { getValue: () => any }) => ReactNode;
};

type TabDef = {
  key: string;
  label: string;
  countKey?: string;
  countable?: boolean;
  testId?: string;
};
type RowAction = {
  label: string;
  onClick?: (_row: any) => void;
  disabled?: boolean;
  danger?: boolean;
  icon?: ReactNode;
};

type OverviewTableWithPanelProps = {
  columns: ColumnDef[];
  data: any[];
  tabs?: TabDef[];
  renderPanelContent?: (_row: any, _tab: string, _panelApi: { activeTab: string; setActiveTab: (_key: string) => void; tabCounts: Record<string, number> }) => ReactNode;
  panelHeader?: (_row: any) => ReactNode;
  title: string;
  resourceKind?: string;
  namespace?: string;
  loading?: boolean;
  error?: string | null;
  onCreateResource?: () => void;
  createPlatform?: 'k8s' | 'swarm';
  createKind?: string;
  createButtonTitle?: string;
  createNotice?: string | { message: string; type?: 'success' | 'error' | 'warning'; duration?: number };
  createHint?: string;
  tableTestId?: string;
  headerActions?: ReactNode;
  getRowActions?: (_row: any, _api: { openDetails: (_tabKey?: string) => void; setActiveTab: (_key: string) => void }) => RowAction[];
  tabCountsFetcher?: (_row: any) => Promise<Record<string, number>> | Record<string, number>;
  enableTabCounts?: boolean;
  bulkActions?: BulkAction[];
  bulkResourceKind?: string;
};

/**
 * Reusable overview table with bottom panel.
 */
export default function OverviewTableWithPanel({
  columns,
  data,
  tabs,
  renderPanelContent,
  panelHeader,
  title,
  resourceKind,
  namespace,
  loading,
  onCreateResource,
  createPlatform = 'k8s',
  createKind,
  createButtonTitle,
  createNotice,
  createHint,
  tableTestId,
  headerActions,
  getRowActions,
  tabCountsFetcher,
  enableTabCounts = true,
  bulkActions,
  bulkResourceKind,
}: OverviewTableWithPanelProps) {
  const [bottomOpen, setBottomOpen] = useState(false);
  const [selectedRow, setSelectedRow] = useState<any | null>(null);
  const safeTabs = Array.isArray(tabs) && tabs.length > 0 ? tabs : [{ key: 'summary', label: 'Summary' }];
  const [activeTab, setActiveTab] = useState(safeTabs[0]?.key || 'summary');
  // Filter text state
  const [filterText, setFilterText] = useState('');
  // Create overlay state
  const [showCreate, setShowCreate] = useState(false);
  // Row actions menu
  const [openMenuKey, setOpenMenuKey] = useState<string | null>(null);
  // Tab counts state
  const [tabCounts, setTabCounts] = useState<Record<string, number>>({});
  const [tabCountsLoading, setTabCountsLoading] = useState(false);

  const defaultSortKey = useMemo(() => pickDefaultSortKey(columns), [columns]);
  const [sortState, setSortState] = useState(() => ({ key: defaultSortKey, direction: 'asc' as 'asc' | 'desc' }));

  useEffect(() => {
    if (!defaultSortKey) return;
    setSortState((cur) => {
      const curKey = cur?.key;
      const hasKey = columns.some((col) => getColumnKey(col) === curKey);
      if (curKey && hasKey) return cur;
      return { key: defaultSortKey, direction: 'asc' };
    });
  }, [columns, defaultSortKey]);

  const openBottomPanel = (row: any) => {
    setSelectedRow(row);
    setBottomOpen(true);
    setActiveTab(safeTabs[0]?.key || 'summary');
  };

  const openBottomPanelAtTab = (row: any, tabKey?: string) => {
    setSelectedRow(row);
    setBottomOpen(true);
    if (tabKey) setActiveTab(tabKey);
    else setActiveTab(safeTabs[0]?.key || 'summary');
  };

  const closeBottomPanel = () => {
    setBottomOpen(false);
    setSelectedRow(null);
    setActiveTab(safeTabs[0]?.key || 'summary'); // Reset to default tab
    setTabCounts({}); // Clear tab counts when closing
  };

  const closeRowMenu = () => {
    setOpenMenuKey(null);
  };

  useEffect(() => {
    if (!bottomOpen) return;
    const handleClick = (e: MouseEvent) => {
      const target = e.target as HTMLElement | null;
      // Don't close if we're resizing or if the click is within the bottom panel
      if (target?.closest('.bottom-panel') ||
          target?.closest('[data-resizing]') ||
          document.body.style.cursor === 'ns-resize') {
        return;
      }
      closeBottomPanel();
    };

    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        closeBottomPanel();
      }
    };

    document.addEventListener('mousedown', handleClick);
    document.addEventListener('keydown', handleKeyDown);
    return () => {
      document.removeEventListener('mousedown', handleClick);
      document.removeEventListener('keydown', handleKeyDown);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [bottomOpen]);

  // Close the row actions menu when clicking outside or pressing Escape
  useEffect(() => {
    if (!openMenuKey) return;

    const handleClick = (e: MouseEvent) => {
      const target = e.target as HTMLElement | null;
      if (target?.closest('.row-actions-menu') || target?.closest('.row-actions-button')) return;
      closeRowMenu();
    };

    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        closeRowMenu();
      }
    };

    const handleFocusIn = (e: FocusEvent) => {
      const target = e.target as HTMLElement | null;
      if (target?.closest('.row-actions-menu') || target?.closest('.row-actions-button')) return;
      closeRowMenu();
    };

    const handleWindowBlur = () => {
      closeRowMenu();
    };

    document.addEventListener('mousedown', handleClick);
    document.addEventListener('keydown', handleKeyDown);
    document.addEventListener('focusin', handleFocusIn);
    window.addEventListener('blur', handleWindowBlur);
    return () => {
      document.removeEventListener('mousedown', handleClick);
      document.removeEventListener('keydown', handleKeyDown);
      document.removeEventListener('focusin', handleFocusIn);
      window.removeEventListener('blur', handleWindowBlur);
    };
  }, [openMenuKey]);

  // Fetch tab counts when a row is selected
  useEffect(() => {
    if (!selectedRow || !enableTabCounts) {
      setTabCounts({});
      return;
    }

    // Check if any tabs are countable
    const hasCountableTabs = safeTabs.some(t => t.countable !== false && t.countKey);
    if (!hasCountableTabs) {
      return;
    }

    if (!tabCountsFetcher && !resourceKind) {
      return;
    }

    const kind = resourceKind || 'Unknown';
    const name = (selectedRow as any)?.name || (selectedRow as any)?.Name;
    const ns = (selectedRow as any)?.namespace || (selectedRow as any)?.Namespace;

    let cancelled = false;
    // Only show loading indicator on initial load (when no counts exist)
    // This prevents badge flickering when counts are being refreshed
    const isInitialLoad = Object.keys(tabCounts).length === 0;
    if (isInitialLoad) {
      setTabCountsLoading(true);
    }

    const fetchCounts = async () => {
      if (typeof tabCountsFetcher === 'function') {
        return await tabCountsFetcher(selectedRow);
      }
      if (!name) {
        return {} as Record<string, number>;
      }
      return fetchTabCounts(kind, ns, name);
    };

    Promise.resolve()
      .then(fetchCounts)
      .then((counts) => {
        if (!cancelled) {
          setTabCounts(counts || {});
        }
      })
      .catch(() => {
        if (!cancelled) {
          // Keep existing counts on error to prevent flicker
          // Only clear if this was the initial load
          if (isInitialLoad) {
            setTabCounts({});
          }
        }
      })
      .finally(() => {
        if (!cancelled) {
          setTabCountsLoading(false);
        }
      });

    return () => {
      cancelled = true;
    };
  }, [selectedRow, enableTabCounts, resourceKind, safeTabs, tabCountsFetcher]);

  // Memoized filter to avoid flicker and unnecessary recomputation
  const normalizedFilter = filterText.trim().toLowerCase();
  const filteredData = useMemo(() => {
    if (!normalizedFilter) return data;
    try {
      return data.filter((row) =>
        columns.some((col) => {
          const value = (row as any)?.[col.accessorKey || col.key as string];
          if (value === null || value === undefined) return false;
          return String(value).toLowerCase().includes(normalizedFilter);
        })
      );
    } catch {
      return data;
    }
  }, [data, columns, normalizedFilter]);

  const sortedData = useMemo(() => {
    if (!sortState?.key) return filteredData;
    return sortRows(filteredData, sortState.key, sortState.direction);
  }, [filteredData, sortState]);

  const getRowKey = (row: any, _idx: number) => {
    // Prefer stable unique identifiers: metadata.uid or provided uid fields.
    // Fallback to namespace + name which is also stable across sorts.
    const ns = row?.namespace || row?.Namespace || '';
    const uid = row?.uid ?? row?.UID ?? row?.metadata?.uid ?? null;
    const name = row?.id ?? row?.name ?? row?.Name ?? null;
    if (uid) return String(uid);
    if (name) return ns ? `${ns}/${String(name)}` : String(name);
    // Last resort: JSON-stringify the row to produce a deterministic key
    return String(JSON.stringify(row));
  };

  const resolvedBulkActions = useMemo(() => {
    if (Array.isArray(bulkActions)) return bulkActions;
    const inferredKind = bulkResourceKind || resourceKind || createKind;
    return getBulkActionsForResource({ platform: createPlatform, kind: inferredKind });
  }, [bulkActions, bulkResourceKind, resourceKind, createKind, createPlatform]);

  const bulkEnabled = resolvedBulkActions.length > 0;
  const selection: any = useTableSelection(data, getRowKey, sortedData);
  const selectAllRef = useRef<HTMLInputElement | null>(null);

  useEffect(() => {
    if (!bulkEnabled || !selectAllRef.current) return;
    selectAllRef.current.indeterminate = selection.isIndeterminate;
  }, [bulkEnabled, selection.isIndeterminate, selection.isAllSelected]);

  useEffect(() => {
    if (!bulkEnabled) return;
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.key.toLowerCase() === 'a') {
        e.preventDefault();
        selection.toggleAll();
        return;
      }
      if (e.key === 'Escape') {
        selection.clearSelection();
      }
    };

    document.addEventListener('keydown', handleKeyDown);
    return () => {
      document.removeEventListener('keydown', handleKeyDown);
    };
  }, [bulkEnabled, selection]);

  const handleOpenCreate = () => {
    if (typeof onCreateResource === 'function') {
      onCreateResource();
      return;
    }
    if (createNotice) {
      const notice = typeof createNotice === 'string' ? { message: createNotice } : createNotice;
      const message = notice?.message;
      if (message) {
        showNotification(message, {
          type: notice?.type || 'warning',
          duration: typeof notice?.duration === 'number' ? notice.duration : 3000,
        });
      }
    }
    setShowCreate(true);
  };

  const handleBulkAction = useCallback(async (action: BulkAction) => {
    if (!bulkEnabled || !action) return;
    const selectedRows = selection.getSelectedRows(sortedData);
    if (selectedRows.length === 0) return;

    if (action.confirm) {
      const ok = window.confirm(`${action.label} ${selectedRows.length} selected item(s)?`);
      if (!ok) return;
    }

    const options: Record<string, any> = {};
    if (action.promptReplicas) {
      const current = selectedRows[0]?.replicas ?? selectedRows[0]?.Replicas ?? 0;
      const raw = window.prompt('Enter desired replica count:', String(current ?? 0));
      if (raw === null) return;
      const parsed = Number(raw);
      if (!Number.isFinite(parsed) || parsed < 0) {
        showError('Replica count must be a non-negative number.');
        return;
      }
      options.replicas = Math.floor(parsed);
    }

    try {
      const summary = await executeBulkAction({
        platform: createPlatform,
        kind: bulkResourceKind || resourceKind || createKind,
        actionKey: action.key,
        rows: selectedRows,
        options,
      });
      if (summary.failed === 0) {
        showSuccess(`${action.label} succeeded for ${summary.succeeded} item(s).`);
      } else {
        showError(`${action.label} completed with ${summary.failed} failure(s).`);
      }
      selection.clearSelection();
    } catch (err: any) {
      showError(`${action.label} failed: ${err?.message || String(err)}`);
    }
  }, [bulkEnabled, selection, sortedData, createPlatform, resourceKind, createKind, bulkResourceKind]);

  const buildMenuActions = (row: any) => {
    const api = {
      openDetails: (tabKey?: string) => openBottomPanelAtTab(row, tabKey),
      setActiveTab,
    };
    const extra = typeof getRowActions === 'function' ? (getRowActions(row, api) || []) : [];
    const normalizedExtra = Array.isArray(extra) ? extra.filter(Boolean) : [];
    // Removed Close item - menu closes automatically on click outside, focus loss, or Escape
    return [
      { label: 'Details', icon: '🔎', onClick: () => openBottomPanel(row) },
      ...normalizedExtra,
    ];
  };

  return (
    <div>
      <div className="overview-header">
        {/* Left: create button */}
        <div className="overview-left">
          <button
            title={createButtonTitle || 'Create new'}
            aria-label="Create new"
            onClick={handleOpenCreate}
            className="overview-create-btn"
          >
            +
          </button>
          {bulkEnabled && (
            <BulkActionBar
              selectedCount={selection.selectedCount}
              actions={resolvedBulkActions}
              onAction={handleBulkAction}
              onClear={selection.clearSelection}
            />
          )}
        </div>
        <h2 className="overview-title">{title}</h2>
        <div className="overview-actions">
          {headerActions}
          <input
            type="search"
            placeholder="Filter..."
            aria-label="Filter table"
            value={filterText}
            onChange={(e) => setFilterText(e.target.value)}
          />
        </div>
      </div>

      <table className="gh-table" data-testid={tableTestId}>
        <colgroup>
          {bulkEnabled && <col className="bulk-checkbox-col" />}
          {columns.map((col, idx) => (
            <col key={col.accessorKey || col.key || idx} style={{ width: col.width || 'auto' }} />
          ))}
          <col className="overview-actions-col" />
        </colgroup>
        <thead>
          <tr>
            {bulkEnabled && (
              <th className="bulk-checkbox-col" aria-label="Select all">
                <input
                  ref={selectAllRef}
                  className="bulk-select-all"
                  type="checkbox"
                  checked={selection.isAllSelected}
                  onChange={() => selection.toggleAll()}
                  onClick={(e) => e.stopPropagation()}
                />
              </th>
            )}
            {columns.map((col) => {
              const key = col.accessorKey || col.key;
              const isActive = key && sortState?.key === key;
              const direction = isActive ? sortState?.direction : undefined;
              return (
                <th key={key || col.header || col.label} aria-sort={direction === 'asc' ? 'ascending' : direction === 'desc' ? 'descending' : 'none'}>
                  <button
                    type="button"
                    className="sortable-header"
                    onClick={() => key && setSortState((cur) => toggleSortState(cur, key))}
                  >
                    <span>{col.header || col.label}</span>
                    <span className="sortable-indicator" aria-hidden="true">
                      {isActive ? (direction === 'asc' ? '▲' : '▼') : '↕'}
                    </span>
                  </button>
                </th>
              );
            })}
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {data.length === 0 && !loading && (
            <tr>
              <td colSpan={columns.length + 1 + (bulkEnabled ? 1 : 0)} className="main-panel-loading" style={{ textAlign: 'center', padding: '2rem', color: 'var(--gh-table-text, #e0e0e0)' }}>
                No {title || resourceKind} deployed in this namespace
              </td>
            </tr>
          )}
          {sortedData.map((row: any, idx: number) => (
            !row ? null : (
              <tr
                key={getRowKey(row, idx)}
                className={bulkEnabled && selection.isSelected(getRowKey(row, idx)) ? 'bulk-selected' : undefined}
                onClick={(e) => {
                  if (bulkEnabled && e.shiftKey) {
                    e.preventDefault();
                    selection.toggleRow(getRowKey(row, idx), idx, true);
                    return;
                  }
                  openBottomPanel(row);
                }}
              >
                {bulkEnabled && (
                  <td className="bulk-checkbox-col" onClick={(e) => e.stopPropagation()}>
                    <input
                      className="bulk-row-checkbox"
                      type="checkbox"
                      checked={selection.isSelected(getRowKey(row, idx))}
                      onClick={(e) => {
                        e.stopPropagation();
                        selection.toggleRow(getRowKey(row, idx), idx, e.shiftKey);
                      }}
                      onChange={() => {}}
                    />
                  </td>
                )}
                {columns.map((col, colIdx) => (
                  <td key={`${row.name || idx}-${col.accessorKey || col.key || colIdx}`}>
                    {(() => {
                      const key = col.accessorKey || col.key;
                      const rawValue = key ? row[key] : undefined;
                      if (!col.cell && key && STATUS_BADGE_KEYS.has(String(key).toLowerCase())) {
                        if (rawValue === null || rawValue === undefined || rawValue === '') return '-';
                        return <StatusBadge status={String(rawValue)} size="small" />;
                      }
                      if (!key) return rawValue;
                      return col.cell ? col.cell({ getValue: () => row[key] }) : rawValue;
                    })()}
                  </td>
                ))}
                <td className="row-actions-cell">
                  <button
                    type="button"
                    className="row-actions-button"
                    aria-label="Row actions"
                    title="Actions"
                    onClick={(e) => {
                      e.stopPropagation();
                      const key = getRowKey(row, idx);
                      setOpenMenuKey((cur) => (cur === key ? null : key));
                    }}
                  >···
                  </button>

                  {openMenuKey === getRowKey(row, idx) && (
                    <div
                      className="menu-content row-actions-menu"
                      onClick={(e) => e.stopPropagation()}
                    >
                      {(() => {
                        const menuActions = buildMenuActions(row);
                        return menuActions.map((a: RowAction, i: number) => {
                        const disabled = Boolean(a?.disabled);
                        const danger = Boolean(a?.danger);
                        const itemClassName = `context-menu-item${disabled ? ' is-disabled' : ''}${danger ? ' is-danger' : ''}`;
                        return (
                          <div
                            key={`${a?.label || 'action'}-${i}`}
                            className={itemClassName}
                            onClick={() => {
                              if (disabled) return;
                              try {
                                a?.onClick?.(row);
                              } finally {
                                closeRowMenu();
                              }
                            }}
                          >
                            {a?.icon ? (
                              <span aria-hidden="true" className="context-menu-icon">{a.icon}</span>
                            ) : (
                              <span aria-hidden="true" className="context-menu-icon" />
                            )}
                            <span>{a?.label}</span>
                          </div>
                        );
                        });
                      })()}
                    </div>
                  )}
                </td>
              </tr>
            )
          ))}
          {filteredData.length === 0 && data.length > 0 && (
            <tr>
              <td colSpan={columns.length + 1 + (bulkEnabled ? 1 : 0)} className="main-panel-loading">No rows match the filter.</td>
            </tr>
          )}
        </tbody>
      </table>
      <BottomPanel
        open={bottomOpen}
        onClose={closeBottomPanel}
        tabs={safeTabs}
        activeTab={activeTab}
        onTabChange={setActiveTab}
        headerRight={selectedRow && panelHeader ? panelHeader(selectedRow) : null}
        tabCounts={tabCounts}
        tabCountsLoading={tabCountsLoading}
      >
        {selectedRow && typeof renderPanelContent === 'function'
          ? renderPanelContent(selectedRow, activeTab, { activeTab, setActiveTab, tabCounts })
          : null}
      </BottomPanel>

      {/* Create manifest overlay */}
      <CreateManifestOverlay
        open={showCreate}
        platform={createPlatform}
        kind={createKind ?? resourceKind}
        namespace={namespace}
        createHint={createHint}
        onClose={() => setShowCreate(false)}
      />
    </div>
  );
}

import type { ReactNode } from 'react';
import { createContext, useCallback, useContext, useEffect, useReducer } from 'react';
import { showError, showSuccess } from '../notification';
import type { MCPConfig, MCPStatus } from './mcpApi';
import {
    GetMCPConfig,
    GetMCPStatus,
    SetMCPConfig,
    StartMCPServer,
    StopMCPServer,
} from './mcpApi';

// ─── State ───────────────────────────────────────────────────────────────────

interface MCPState {
  config: MCPConfig | null;
  status: MCPStatus | null;
  loading: boolean;
  error: string | null;
  showConfig: boolean;
}

const initialState: MCPState = {
  config: null,
  status: null,
  loading: false,
  error: null,
  showConfig: false,
};

// ─── Actions ─────────────────────────────────────────────────────────────────

type MCPAction =
  | { type: 'SET_CONFIG'; config: MCPConfig }
  | { type: 'SET_STATUS'; status: MCPStatus }
  | { type: 'SET_LOADING'; loading: boolean }
  | { type: 'SET_ERROR'; error: string | null }
  | { type: 'SHOW_CONFIG' }
  | { type: 'HIDE_CONFIG' };
function reducer(state: MCPState, action: MCPAction): MCPState {
  switch (action.type) {
    case 'SET_CONFIG':
      return { ...state, config: action.config, loading: false, error: null };
    case 'SET_STATUS':
      return { ...state, status: action.status };
    case 'SET_LOADING':
      return { ...state, loading: action.loading };
    case 'SET_ERROR':
      return { ...state, error: action.error, loading: false };
    case 'SHOW_CONFIG':
      return { ...state, showConfig: true };
    case 'HIDE_CONFIG':
      return { ...state, showConfig: false };
    default:
      return state;
  }
}

// ─── Context ─────────────────────────────────────────────────────────────────

interface MCPContextValue {
  state: MCPState;
  loadConfig: () => Promise<void>;
  saveConfig: (_config: MCPConfig) => Promise<void>;
  startServer: () => Promise<void>;
  stopServer: () => Promise<void>;
  showConfigModal: () => void;
  hideConfigModal: () => void;
}

const MCPContext = createContext<MCPContextValue | null>(null);

// ─── Provider ────────────────────────────────────────────────────────────────

export function MCPProvider({ children }: { children: ReactNode }) {
  const [state, dispatch] = useReducer(reducer, initialState);

  // Load config on mount
  const loadConfig = useCallback(async () => {
    dispatch({ type: 'SET_LOADING', loading: true });
    try {
      const config = await GetMCPConfig();
      dispatch({ type: 'SET_CONFIG', config });
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      dispatch({ type: 'SET_ERROR', error: msg });
    }
  }, []);

  useEffect(() => {
    loadConfig();
  }, [loadConfig]);

  // Poll status every 10s when enabled
  useEffect(() => {
    if (!state.config?.enabled) return;

    let active = true;
    const poll = async () => {
      try {
        const status = await GetMCPStatus();
        if (active) dispatch({ type: 'SET_STATUS', status });
      } catch {
        // Ignore polling errors
      }
    };
    poll();
    const id = setInterval(poll, 10_000);
    return () => {
      active = false;
      clearInterval(id);
    };
  }, [state.config?.enabled]);

  const saveConfig = useCallback(async (config: MCPConfig) => {
    dispatch({ type: 'SET_LOADING', loading: true });
    try {
      await SetMCPConfig(config);
      dispatch({ type: 'SET_CONFIG', config });
      showSuccess('MCP configuration saved');
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      dispatch({ type: 'SET_ERROR', error: msg });
      showError(`Failed to save MCP config: ${msg}`);
      throw err;
    }
  }, []);

  const startServer = useCallback(async () => {
    try {
      await StartMCPServer();
      const status = await GetMCPStatus();
      dispatch({ type: 'SET_STATUS', status });
      showSuccess('MCP server started');
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      showError(`Failed to start MCP server: ${msg}`);
    }
  }, []);

  const stopServer = useCallback(async () => {
    try {
      await StopMCPServer();
      const status = await GetMCPStatus();
      dispatch({ type: 'SET_STATUS', status });
      showSuccess('MCP server stopped');
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      showError(`Failed to stop MCP server: ${msg}`);
    }
  }, []);

  const showConfigModal = useCallback(() => {
    dispatch({ type: 'SHOW_CONFIG' });
  }, []);

  const hideConfigModal = useCallback(() => {
    dispatch({ type: 'HIDE_CONFIG' });
  }, []);

  const value: MCPContextValue = {
    state,
    loadConfig,
    saveConfig,
    startServer,
    stopServer,
    showConfigModal,
    hideConfigModal,
  };

  return <MCPContext.Provider value={value}>{children}</MCPContext.Provider>;
}

// ─── Hook ────────────────────────────────────────────────────────────────────

export function useMCP(): MCPContextValue {
  const ctx = useContext(MCPContext);
  if (!ctx) {
    throw new Error('useMCP must be used within <MCPProvider>');
  }
  return ctx;
}

import { createContext, useCallback, useContext, useEffect, useState } from 'react';

/**
 * Default application settings.
 */
const defaultSettings = {
  // Polling intervals (milliseconds)
  fastPollingInterval: 1000,      // For newly created resources
  slowPollingInterval: 60000,     // For stable resources after first minute
  normalRefreshInterval: 5000,    // Standard refresh rate

  // UI preferences
  showTimestampsRelative: true,   // Show "2 minutes ago" vs "2024-01-15 10:30:00"
  tableRowsPerPage: 50,           // Default rows per page in tables
  animationsEnabled: true,        // Enable/disable UI animations

  // Logging
  verboseLogging: false,          // Enable verbose console logging

  // Theme (for future use)
  theme: 'system',                // 'light', 'dark', 'system'
};

type Settings = typeof defaultSettings;

const STORAGE_KEY = 'kubedevbench_settings';

type SettingsContextValue = {
  settings: Settings;
  updateSetting: <K extends keyof Settings>(_key: K, _value: Settings[K]) => void;
  updateSettings: (_updates: Partial<Settings>) => void;
  resetSettings: () => void;
  defaultSettings: Settings;
};
const SettingsContext = createContext<SettingsContextValue | null>(null);

/**
 * Load settings from localStorage.
 * @returns {Object} Merged settings (defaults + stored)
 */
function loadSettings(): Settings {
  try {
    const stored = localStorage.getItem(STORAGE_KEY);
    if (stored) {
      const parsed = JSON.parse(stored) as Partial<Settings>;
      return { ...defaultSettings, ...parsed };
    }
  } catch {
    // Ignore parse errors, return defaults
  }
  return { ...defaultSettings };
}

/**
 * Save settings to localStorage.
 * @param {Object} settings - Settings to save
 */
function saveSettings(settings: Settings) {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(settings));
  } catch {
    // Ignore storage errors (e.g., quota exceeded)
  }
}

/**
 * SettingsProvider component.
 * Provides application-wide settings context.
 */
export function SettingsProvider({ children }: { children: React.ReactNode }) {
  const [settings, setSettingsState] = useState<Settings>(loadSettings);

  // Update a single setting
  const updateSetting = useCallback(<K extends keyof Settings>(key: K, value: Settings[K]) => {
    setSettingsState((prev) => {
      const next = { ...prev, [key]: value } as Settings;
      saveSettings(next);
      return next;
    });
  }, []);

  // Update multiple settings at once
  const updateSettings = useCallback((updates: Partial<Settings>) => {
    setSettingsState((prev) => {
      const next = { ...prev, ...updates } as Settings;
      saveSettings(next);
      return next;
    });
  }, []);

  // Reset all settings to defaults
  const resetSettings = useCallback(() => {
    setSettingsState({ ...defaultSettings });
    saveSettings(defaultSettings);
  }, []);

  // Listen for storage changes from other tabs
  useEffect(() => {
    const handleStorageChange = (e: StorageEvent) => {
      if (e.key === STORAGE_KEY) {
        setSettingsState(loadSettings());
      }
    };

    window.addEventListener('storage', handleStorageChange);
    return () => window.removeEventListener('storage', handleStorageChange);
  }, []);

  const value: SettingsContextValue = {
    settings,
    updateSetting,
    updateSettings,
    resetSettings,
    defaultSettings,
  };

  return (
    <SettingsContext.Provider value={value}>
      {children}
    </SettingsContext.Provider>
  );
}

/**
 * Hook to access settings context.
 * @returns {{ settings: Object, updateSetting: Function, updateSettings: Function, resetSettings: Function }}
 */
export function useSettings() {
  const context = useContext(SettingsContext);
  if (!context) {
    throw new Error('useSettings must be used within a SettingsProvider');
  }
  return context;
}

/**
 * Hook to get a specific setting value with a fallback to default.
 * Useful when settings context might not be available.
 * @param {string} key - Setting key
 * @returns {*} The setting value
 */
export function useSetting<K extends keyof Settings>(key: K) {
  const context = useContext(SettingsContext);
  if (context) {
    return context.settings[key] ?? defaultSettings[key];
  }
  return defaultSettings[key];
}

export { defaultSettings };
export default SettingsContext;

/**
 * Logger utility for production-safe logging.
 * In development, logs are output to console.
 * In production, logs are suppressed to avoid console noise.
 */

const isDev = import.meta.env?.DEV ?? false;

type LogMethod = (...args: unknown[]) => void;
type Logger = {
  log: LogMethod;
  info: LogMethod;
  warn: LogMethod;
  error: LogMethod;
  debug: LogMethod;
  trace: LogMethod;
  table: LogMethod;
  group: LogMethod;
  groupEnd: () => void;
  groupCollapsed: LogMethod;
  time: (label?: string) => void;
  timeEnd: (label?: string) => void;
};
/**
 * Logger object with methods matching console API.
 * Logs are only output in development mode.
 */
export const logger: Logger = {
  /**
   * Log a message (equivalent to console.log)
   * @param  {...any} args - Arguments to log
   */
  log: (...args: unknown[]) => {
    if (isDev) {
      globalThis.console.log(...args);
    }
  },

  /**
   * Log an info message (equivalent to console.info)
   * @param  {...any} args - Arguments to log
   */
  info: (...args: unknown[]) => {
    if (isDev) {
      globalThis.console.info(...args);
    }
  },

  /**
   * Log a warning message (equivalent to console.warn)
   * @param  {...any} args - Arguments to log
   */
  warn: (...args: unknown[]) => {
    if (isDev) {
      globalThis.console.warn(...args);
    }
  },

  /**
   * Log an error message (equivalent to console.error)
   * In production, errors are still logged for debugging critical issues.
   * @param  {...any} args - Arguments to log
   */
  error: (...args: unknown[]) => {
    // Always log errors, even in production
    globalThis.console.error(...args);
  },

  /**
   * Log a debug message (equivalent to console.debug)
   * @param  {...any} args - Arguments to log
   */
  debug: (...args: unknown[]) => {
    if (isDev) {
      globalThis.console.debug(...args);
    }
  },

  /**
   * Log a trace message (equivalent to console.trace)
   * @param  {...any} args - Arguments to log
   */
  trace: (...args: unknown[]) => {
    if (isDev) {
      globalThis.console.trace(...args);
    }
  },

  /**
   * Log a table (equivalent to console.table)
   * @param  {...any} args - Arguments to log
   */
  table: (...args: unknown[]) => {
    if (isDev) {
      globalThis.console.table(...args);
    }
  },

  /**
   * Start a timer group (equivalent to console.group)
   * @param  {...any} args - Arguments to log
   */
  group: (...args: unknown[]) => {
    if (isDev) {
      globalThis.console.group(...args);
    }
  },

  /**
   * End a timer group (equivalent to console.groupEnd)
   */
  groupEnd: () => {
    if (isDev) {
      globalThis.console.groupEnd();
    }
  },

  /**
   * Start a collapsed group (equivalent to console.groupCollapsed)
   * @param  {...any} args - Arguments to log
   */
  groupCollapsed: (...args: unknown[]) => {
    if (isDev) {
      globalThis.console.groupCollapsed(...args);
    }
  },

  /**
   * Start a timer (equivalent to console.time)
   * @param {string} label - Timer label
   */
  time: (label?: string) => {
    if (isDev) {
      globalThis.console.time(label ?? 'default');
    }
  },

  /**
   * End a timer (equivalent to console.timeEnd)
   * @param {string} label - Timer label
   */
  timeEnd: (label?: string) => {
    if (isDev) {
      globalThis.console.timeEnd(label ?? 'default');
    }
  },
};

export default logger;
